import React, { useState } from "react";
import axios from "axios";
import "./LabSearch.css";

const LabSearch = ({ goBack }) => {
  const [lab, setLab] = useState("");
  const [day, setDay] = useState("");
  const [period, setPeriod] = useState("");
  const [results, setResults] = useState(null);
  const [error, setError] = useState("");

  const handleSearch = async () => {
    if (!lab || !day || !period) {
      setError("Please enter lab name, day, and period.");
      return;
    }
    setError("");

    try {
      const response = await axios.get("/api/check-lab-availability", {
        params: { lab, day, period },
      });
      setResults(response.data);
    } catch (error) {
      console.error("Error fetching lab data:", error);
      setError("Failed to fetch lab data. Try again.");
    }
  };

  return (
    <div className="lab-search">
      <h2>Check Lab Availability</h2>
      <div className="form-group">
        <label>Lab Name:</label>
        <input
          type="text"
          value={lab}
          onChange={(e) => setLab(e.target.value)}
          placeholder="Enter lab name (e.g., Programming Lab)"
        />
      </div>
      
      <div className="form-group">
        <label>Day:</label>
        <select value={day} onChange={(e) => setDay(e.target.value)}>
          <option value="">Select Day</option>
          <option value="Monday">Monday</option>
          <option value="Tuesday">Tuesday</option>
          <option value="Wednesday">Wednesday</option>
          <option value="Thursday">Thursday</option>
          <option value="Friday">Friday</option>
        </select>
      </div>

      <div className="form-group">
        <label>Period:</label>
        <input
          type="number"
          value={period}
          onChange={(e) => setPeriod(e.target.value)}
          placeholder="Enter period (1-8)"
          min="1"
          max="8"
        />
      </div>

      {error && <p className="error">{error}</p>}

      <div className="button-group">
        <button onClick={handleSearch}>Search</button>
        <button onClick={goBack}>Back</button>
      </div>
      
      {results && (
        <div className="results">
          <h3>Results:</h3>
          {results.message && <p>{results.message}</p>}
          {results.labDetails && (
            <div className="details">
              <p><strong>Lab:</strong> {results.labDetails.lab}</p>
              <p><strong>Faculty:</strong> {results.labDetails.faculty}</p>
              <p><strong>Subject:</strong> {results.labDetails.subject}</p>
              <p><strong>Year:</strong> {results.labDetails.year}</p>
              <p><strong>Section:</strong> {results.labDetails.section}</p>
              <p><strong>Period:</strong> {results.labDetails.period}</p>
            </div>
          )}
          {results.alternative && <p><strong>Alternative:</strong> {results.alternative}</p>}
        </div>
      )}
    </div>
  );
};

export default LabSearch;
